import { useEffect, useMemo, useState } from 'react';
import type { SelectOption } from '@linm-soft/common-components';
import { dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { CustomerDto, CustomerGroupDto } from '../../../services/master/models';
import { buildCustomerCodePlaceholder } from '../../../utils/customerCodeFormat';
import {
  clearCustomerGroupsFromLevel,
  customerGroupLevelKeys,
  normalizeCustomerGroupDto,
  resolveCustomerGroupChainDepth,
  resolveCustomerGroupChainPatch,
  resolveLeafCustomerGroupId,
  resolveLevel1FormatCode,
} from '../../../utils/customerGroupTree';

export type CustomerFormErrors = Partial<Record<'code' | 'name' | 'customerGroupId', string>>;

export type CustomerFormState = Partial<CustomerDto> & {
  customerGroup1Id?: string;
  customerGroup1Code?: string;
  customerGroup1Name?: string;
  customerGroup2Id?: string;
  customerGroup2Code?: string;
  customerGroup2Name?: string;
  customerGroup3Id?: string;
  customerGroup3Code?: string;
  customerGroup3Name?: string;
  customerGroup4Id?: string;
  customerGroup4Code?: string;
  customerGroup4Name?: string;
};

export interface UseCustomerFormOptions {
  editing?: CustomerDto | null;
  initialName?: string;
  defaultCustomerType?: string;
  initFormName?: 'create-customer' | 'edit-customer';
  listGroupOptions?: SelectOption[];
  onSaved: (customer: CustomerDto) => void;
  markClean?: () => void;
}

const emptyGroupLevels = clearCustomerGroupsFromLevel(1);

const DEFAULT_CODE_PLACEHOLDER = buildCustomerCodePlaceholder();

function syncCustomerGroupId(form: CustomerFormState): CustomerFormState {
  const leafId = resolveLeafCustomerGroupId(form);
  return { ...form, customerGroupId: leafId };
}

export function useCustomerForm({
  editing = null,
  initialName = '',
  defaultCustomerType = 'Customer',
  listGroupOptions: _listGroupOptions = [],
  onSaved,
  markClean,
}: UseCustomerFormOptions) {
  const dispatch = useAppDispatch();
  const [customerGroups, setCustomerGroups] = useState<CustomerGroupDto[]>([]);
  const [form, setFormRaw] = useState<CustomerFormState>({ isActive: true });
  const [codePlaceholder, setCodePlaceholder] = useState(DEFAULT_CODE_PLACEHOLDER);
  const [errors, setErrors] = useState<CustomerFormErrors>({});
  const [saving, setSaving] = useState(false);
  /** Nhóm leaf của đối tượng cha — đồng bộ cascade + khóa cấp ≤ depth. */
  const [parentGroupIdForSync, setParentGroupIdForSync] = useState<string | undefined>();
  const [parentGroupLockDepth, setParentGroupLockDepth] = useState(0);

  const setForm = (
    updater: CustomerFormState | ((prev: CustomerFormState) => CustomerFormState),
  ) => {
    setFormRaw(prev => {
      const next = typeof updater === 'function' ? updater(prev) : updater;
      return syncCustomerGroupId(next);
    });
  };

  const groupById = useMemo(() => {
    const map = new Map<string, CustomerGroupDto>();
    for (const g of customerGroups) map.set(g.customerGroupId, normalizeCustomerGroupDto(g));
    return map;
  }, [customerGroups]);

  const leafGroupId = useMemo(() => resolveLeafCustomerGroupId(form), [form]);
  const level1FormatCode = useMemo(
    () => resolveLevel1FormatCode(leafGroupId, customerGroups),
    [leafGroupId, customerGroups],
  );

  useEffect(() => {
    if (editing) return;
    setCodePlaceholder(
      buildCustomerCodePlaceholder(form.parentCode, level1FormatCode),
    );
  }, [editing, form.parentCode, level1FormatCode]);

  useEffect(() => {
    let cancelled = false;
    const timer = setTimeout(() => {
      masterService.getCustomerGroups({ page: 1, pageSize: 500 })
        .then(data => {
          if (!cancelled) {
            setCustomerGroups(data.items.map(g => normalizeCustomerGroupDto(g)));
          }
        })
        .catch(() => { /* non-blocking */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, []);

  useEffect(() => {
    if (editing) {
      const chainPatch = resolveCustomerGroupChainPatch(editing.customerGroupId, customerGroups);
      setForm({
        ...editing,
        ...chainPatch,
        customerGroupId: editing.customerGroupId,
      });
      setErrors({});
      setParentGroupIdForSync(undefined);
      setParentGroupLockDepth(0);
      markClean?.();
      return;
    }
    setForm({
      isActive: true,
      name: initialName.trim(),
      code: '',
      customerType: defaultCustomerType,
      ...emptyGroupLevels,
      customerGroupId: undefined,
    });
    setCodePlaceholder(DEFAULT_CODE_PLACEHOLDER);
    setErrors({});
    setParentGroupIdForSync(undefined);
    setParentGroupLockDepth(0);
    markClean?.();
  }, [editing, initialName, defaultCustomerType, customerGroups, markClean]);

  /** Khi chọn cha trước khi load xong danh sách nhóm — apply chain sau. */
  useEffect(() => {
    if (!parentGroupIdForSync || customerGroups.length === 0) return;
    const chainPatch = resolveCustomerGroupChainPatch(parentGroupIdForSync, customerGroups);
    const depth = resolveCustomerGroupChainDepth(parentGroupIdForSync, customerGroups);
    if (depth === 0) return;
    setParentGroupLockDepth(depth);
    const leafGroup = groupById.get(parentGroupIdForSync);
    setForm(prev => {
      if (!prev.parentId) return prev;
      const lockedPatch: Record<string, string> = {};
      for (let level = 1; level <= depth; level += 1) {
        const keys = customerGroupLevelKeys(level);
        lockedPatch[keys.idKey] = chainPatch[keys.idKey] ?? '';
        lockedPatch[keys.codeKey] = chainPatch[keys.codeKey] ?? '';
        lockedPatch[keys.nameKey] = chainPatch[keys.nameKey] ?? '';
      }
      return {
        ...prev,
        ...lockedPatch,
        customerType: leafGroup?.customerType ?? prev.customerType ?? defaultCustomerType,
      };
    });
  }, [parentGroupIdForSync, customerGroups, groupById, defaultCustomerType]);

  /** Sửa bản ghi có cha — khóa cấp nhóm theo chuỗi nhóm của cha. */
  useEffect(() => {
    if (!editing?.parentId) return;
    let cancelled = false;
    const timer = setTimeout(() => {
      masterService.getCustomerById(editing.parentId!)
        .then(parent => {
          if (cancelled || !parent.customerGroupId) return;
          const depth = resolveCustomerGroupChainDepth(parent.customerGroupId, customerGroups);
          if (depth > 0) {
            setParentGroupLockDepth(depth);
            setParentGroupIdForSync(parent.customerGroupId);
          }
        })
        .catch(() => { /* non-blocking */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [editing?.parentId, editing?.customerId, customerGroups]);

  const clearFieldError = (key: keyof CustomerFormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): CustomerFormErrors => {
    const next: CustomerFormErrors = {};
    if (!form.customerGroup1Id?.trim()) {
      next.customerGroupId = 'Chọn nhóm đối tượng cấp 1';
    } else if (editing && !form.code?.trim()) {
      next.code = 'Nhập mã đối tượng';
    }
    if (!form.name?.trim()) next.name = 'Nhập tên đối tượng';
    return next;
  };

  const applyGroupLevelSelection = (
    level: number,
    code: string,
    name: string,
    groupId: string,
  ) => {
    const keys = customerGroupLevelKeys(level);
    const g = groupById.get(groupId);
    setForm(prev => ({
      ...prev,
      [keys.codeKey]: code,
      [keys.nameKey]: name,
      [keys.idKey]: groupId,
      ...clearCustomerGroupsFromLevel(level + 1),
      customerType: g?.customerType ?? prev.customerType ?? defaultCustomerType,
    }));
    clearFieldError('customerGroupId');
  };

  const clearGroupFromLevel = (level: number) => {
    setForm(prev => ({
      ...prev,
      ...clearCustomerGroupsFromLevel(level),
    }));
  };

  const applyParentSelection = (parent: CustomerDto) => {
    const parentGroupId = parent.customerGroupId?.trim();
    setParentGroupIdForSync(parentGroupId || undefined);
    const chainPatch = parentGroupId
      ? resolveCustomerGroupChainPatch(parentGroupId, customerGroups)
      : {};
    const depth = parentGroupId
      ? resolveCustomerGroupChainDepth(parentGroupId, customerGroups)
      : 0;
    setParentGroupLockDepth(depth);
    const leafGroup = parentGroupId ? groupById.get(parentGroupId) : undefined;
    setForm(prev => ({
      ...prev,
      parentId: parent.customerId,
      parentCode: parent.code,
      parentName: parent.name,
      ...chainPatch,
      ...(depth > 0 ? clearCustomerGroupsFromLevel(depth + 1) : {}),
      customerType:
        leafGroup?.customerType
        ?? parent.customerType
        ?? prev.customerType
        ?? defaultCustomerType,
    }));
    clearFieldError('customerGroupId');
  };

  const clearParentSelection = () => {
    setParentGroupIdForSync(undefined);
    setParentGroupLockDepth(0);
    setForm(prev => ({
      ...prev,
      parentId: undefined,
      parentCode: undefined,
      parentName: undefined,
    }));
  };

  const handleSave = async (): Promise<boolean> => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      return false;
    }
    const g = form.customerGroupId ? groupById.get(form.customerGroupId) : undefined;
    const payload: Partial<CustomerDto> = {
      ...form,
      code: editing ? form.code : undefined,
      customerType: g?.customerType ?? form.customerType ?? defaultCustomerType,
      customerGroupId: form.customerGroupId,
    };
    setSaving(true);
    try {
      const saved = editing
        ? await masterService.updateCustomer(editing.customerId, payload)
        : await masterService.createCustomer(payload);
      markClean?.();
      dispatchAppToast(dispatch, {
        message: editing ? 'Cập nhật đối tượng thành công' : 'Tạo đối tượng thành công',
        type: 'success',
      });
      onSaved(saved);
      return true;
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Lưu thất bại',
        type: 'error',
      });
      return false;
    } finally {
      setSaving(false);
    }
  };

  return {
    form,
    setForm,
    errors,
    saving,
    codePlaceholder,
    clearFieldError,
    applyGroupLevelSelection,
    clearGroupFromLevel,
    applyParentSelection,
    clearParentSelection,
    parentGroupLockDepth,
    handleSave,
  };
}
