import type { AccountSearchApi, AccountSearchRecord } from '@linm-soft/common-components';
import { masterService } from '../../services/master/masterService';
import type { AccountDto } from '../../services/master/models';

/** Single-field label — `152 — Nguyên liệu vật liệu` (align Finance + common-components). */
export function formatAccountDisplay(code: string, name?: string): string {
  const c = code?.trim() ?? '';
  const n = name?.trim() ?? '';
  if (c && n) return `${c} — ${n}`;
  return c || n;
}

function mapAccountSearchRecord(a: AccountDto): AccountSearchRecord {
  return {
    code: a.code,
    name: a.name,
    parentCode: a.parentCode,
    level: a.level,
    isDetail: a.isDetail,
    isActive: a.isActive,
    isSelectable: a.isSelectable ?? true,
    disabledReason: a.disabledReason,
    warningReason: a.warningReason,
    resolvedStandard: a.resolvedStandard,
  };
}

/** Master MFE adapter — `GET /master/accounts`. */
export const erpMasterAccountSearchApi: AccountSearchApi = {
  search: async ({ search, page, pageSize, isActive, isDetail, asOfDate, forPosting }) => {
    const res = await masterService.getAccounts({
      search,
      page,
      pageSize,
      isActive: isActive ?? true,
      isDetail,
      asOfDate,
      forPosting,
    });
    return {
      items: res.items.map(mapAccountSearchRecord),
      page: res.page,
      totalCount: res.totalCount,
    };
  },
  loadCatalog: async (query) => {
    const res = await masterService.getAccounts({
      isActive: true,
      page: 1,
      pageSize: 500,
      asOfDate: query?.asOfDate,
      forPosting: query?.forPosting,
    });
    return res.items.map(mapAccountSearchRecord);
  },
};
