/** Số thứ tự mã đối tượng — 3 chữ số (L1: {group}.### · L2+: {parent}.###). */
export const CUSTOMER_CODE_SEQ_PADDING = 3;

const SEQ_MASK = '#'.repeat(CUSTOMER_CODE_SEQ_PADDING);

/** Mask placeholder — không gọi next-code; BE sinh khi Lưu. */
export function buildCustomerCodePlaceholder(
  parentCode?: string | null,
  level1FormatCode?: string | null,
): string {
  const parent = parentCode?.trim();
  if (parent) return `${parent}.${SEQ_MASK}`;
  const group = level1FormatCode?.trim();
  if (group) return `${group}.${SEQ_MASK}`;
  return `###.${SEQ_MASK}`;
}
