import React, { useEffect, useMemo, useState } from 'react';
import {
  Input,
  Button,
  Checkbox,
  SearchInput,
  useDirtyTracking,
  type OnDirtyChange,
} from '@linm-soft/common-components';
import type { CustomerDto } from '../../../services/master/models';
import { normalizeCode, normalizeCodeOptional } from '../../../utils/codeField';
import { createAccountSearchConfig, formatAccountDisplay } from '../../search';
import { masterService } from '../../../services/master/masterService';
import {
  CatalogCompanyField,
  CatalogFormFooter,
  CatalogFormHistorySlot,
  CatalogLegacyCodeSuffix,
  SharedCatalogFormActions,
  isSharedCatalogReadOnly,
} from '../../catalog';
import type { SharedCatalogFormIntegrationProps } from '../../catalog';
import styles from '../../../styles/erpPage.module.css';
import df from '../../../styles/documentForm.module.css';
import { CustomerParentLookupField } from '../customer/CustomerParentLookupField';
import { CustomerGroupLookupField } from '../customerGroup/CustomerGroupLookupField';
import { useCustomerGroupFormFields } from '../../../hooks/useCustomerGroupFormFields';
import { customerGroupLevelKeys } from '../../../utils/customerGroupTree';
import {
  useCustomerForm,
  type CustomerFormState,
  type UseCustomerFormOptions,
} from './useCustomerForm';

export interface CustomerFormProps extends UseCustomerFormOptions {
  testIdPrefix: string;
  companyName?: string;
  hideCompanyField?: boolean;
  /** FormMode.View — readonly active style, footer Đóng + Lịch sử only */
  readOnly?: boolean;
  sharedCatalog?: SharedCatalogFormIntegrationProps;
  onCancel: () => void;
  onValidationFailed?: () => void;
  onDirtyChange?: OnDirtyChange;
}

/** Form tạo/sửa/xem đối tượng — catalog + search parcel. */
export const CustomerForm: React.FC<CustomerFormProps> = ({
  testIdPrefix,
  editing = null,
  initialName,
  defaultCustomerType,
  initFormName,
  listGroupOptions,
  companyName,
  hideCompanyField = false,
  readOnly: isViewMode = false,
  sharedCatalog,
  onCancel,
  onSaved,
  onValidationFailed,
  onDirtyChange,
}) => {
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const { fields: groupFormFields, loading: groupFieldsLoading } = useCustomerGroupFormFields();
  const {
    form,
    setForm,
    errors,
    saving,
    codePlaceholder,
    clearFieldError,
    applyGroupLevelSelection,
    clearGroupFromLevel,
    applyParentSelection,
    clearParentSelection,
    parentGroupLockDepth,
    handleSave,
  } = useCustomerForm({
    editing,
    initialName,
    defaultCustomerType,
    initFormName,
    listGroupOptions,
    onSaved,
    markClean,
  });

  const sharedReadOnlyRow = editing ? isSharedCatalogReadOnly(editing) : false;
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);
  const [accountName, setAccountName] = useState('');

  /** Cấp 1 = không có đối tượng cha (root). */
  const isRootCustomer = editing ? !editing.parentId : !form.parentId;
  const isEditMode = !!editing && !isViewMode;
  /** Sửa/xem cấp 1 — ẩn lookup cha; tạo mới luôn hiện. */
  const showParentField = !editing || !isRootCustomer;
  /** Sửa — không đổi cha; xem — readonly. */
  const parentFieldDisabled = isViewMode || isEditMode;
  /** Sửa đối tượng cấp 1 — khóa nhóm 1 (đã gắn khi tạo). */
  const lockGroup1OnEdit = isEditMode && isRootCustomer;

  useEffect(() => {
    if (!form.accountCode?.trim()) {
      setAccountName('');
      return;
    }
    let cancelled = false;
    masterService.getAccounts({ search: form.accountCode, page: 1, pageSize: 5, isActive: true })
      .then(res => {
        if (cancelled) return;
        const a = res.items.find(x => x.code === form.accountCode);
        setAccountName(a?.name ?? '');
      })
      .catch(() => { if (!cancelled) setAccountName(''); });
    return () => { cancelled = true; };
  }, [form.accountCode]);

  const onSaveClick = async () => {
    const ok = await handleSave();
    if (!ok && onValidationFailed) onValidationFailed();
  };

  const formGridClass = isViewMode
    ? `${styles.formGrid} ${styles.viewReadOnlySection}`
    : styles.formGrid;

  const groupLevelError = errors.customerGroupId;

  return (
    <>
      <div className={formGridClass}>
        <div className={styles.masterCodeNameRow}>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-code`}>
            <label className={styles.label}>Mã đối tượng *</label>
            {editing || isViewMode ? (
              <Input
                value={form.code ?? ''}
                readOnly
                error={errors.code}
                className={styles.codeInput}
              />
            ) : (
              <Input
                value=""
                readOnly
                disabled
                error={errors.code}
                placeholder={codePlaceholder}
                className={styles.codeInput}
                data-testid={`${testIdPrefix}-code-preview`}
              />
            )}
            <CatalogLegacyCodeSuffix
              testIdPrefix={testIdPrefix}
              code={editing?.code}
              legacyCode={editing?.legacyCode}
            />
          </div>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-name`}>
            <label className={styles.label}>Tên đối tượng *</label>
            <Input
              value={form.name ?? ''}
              readOnly={isViewMode}
              error={errors.name}
              onChange={e => {
                markDirty();
                clearFieldError('name');
                setForm(f => ({ ...f, name: e.target.value }));
              }}
            />
          </div>
        </div>
        {showParentField ? (
          <div
            className={`${styles.formGridFullRow} ${styles.field}`}
            data-testid={`${testIdPrefix}-field-parentId`}
          >
            <label className={styles.label}>Đối tượng cha</label>
            <CustomerParentLookupField
              parentId={form.parentId}
              parentCode={form.parentCode}
              parentName={form.parentName}
              excludeCustomerId={editing?.customerId}
              disabled={parentFieldDisabled}
              onChange={parent => {
                if (parentFieldDisabled) return;
                markDirty();
                applyParentSelection(parent);
              }}
              onClear={() => {
                if (parentFieldDisabled) return;
                markDirty();
                clearParentSelection();
              }}
              testId={`${testIdPrefix}-parent`}
            />
          </div>
        ) : null}
        <div
          className={`${styles.formGridFullRow} ${df.row4}`}
          data-testid={`${testIdPrefix}-customer-group-cascade`}
        >
          {groupFormFields.map(field => {
            const keys = customerGroupLevelKeys(field.level);
            const codeKey = keys.codeKey;
            const nameKey = keys.nameKey;
            const parentGroupIdForLookup =
              field.level > 1
                ? String(
                    form[customerGroupLevelKeys(field.level - 1).idKey as keyof CustomerFormState] ?? '',
                  ) || undefined
                : undefined;
            const showLevelError = field.level === 1 && groupLevelError;
            const groupLockedByParent =
              !!form.parentId && field.level <= parentGroupLockDepth;
            const groupLockedOnEdit =
              lockGroup1OnEdit && field.level === 1;
            return (
              <div key={field.key} className={styles.field} data-testid={`${testIdPrefix}-field-${codeKey}`}>
                <label className={styles.label}>
                  {field.label}
                  {field.level === 1 ? ' *' : ''}
                </label>
                <CustomerGroupLookupField
                  level={field.level}
                  parentGroupId={parentGroupIdForLookup}
                  value={String(form[codeKey as keyof CustomerFormState] ?? '')}
                  displayName={String(form[nameKey as keyof CustomerFormState] ?? '')}
                  disabled={isViewMode || groupFieldsLoading || groupLockedByParent || groupLockedOnEdit}
                  error={showLevelError ? groupLevelError : undefined}
                  onChange={(code, name, groupId) => {
                    markDirty();
                    applyGroupLevelSelection(field.level, code, name, groupId);
                  }}
                  onClear={() => {
                    if (groupLockedOnEdit) return;
                    markDirty();
                    clearGroupFromLevel(field.level);
                    clearFieldError('customerGroupId');
                  }}
                  testId={`${testIdPrefix}-group-${field.level}`}
                />
              </div>
            );
          })}
        </div>
        <div className={styles.masterCodeNameRow}>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-taxCode`}>
            <label className={styles.label}>Mã số thuế</label>
            <Input
              value={form.taxCode ?? ''}
              readOnly={isViewMode}
              className={styles.codeInput}
              onChange={e => {
                markDirty();
                setForm(f => ({ ...f, taxCode: normalizeCodeOptional(e.target.value) }));
              }}
            />
          </div>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-phone`}>
            <label className={styles.label}>Số điện thoại</label>
            <Input
              value={form.phone ?? ''}
              readOnly={isViewMode}
              onChange={e => {
                markDirty();
                setForm(f => ({ ...f, phone: e.target.value }));
              }}
            />
          </div>
        </div>
        <div className={styles.field} data-testid={`${testIdPrefix}-field-address`}>
          <label className={styles.label}>Địa chỉ</label>
          <Input
            value={form.address ?? ''}
            readOnly={isViewMode}
            onChange={e => {
              markDirty();
              setForm(f => ({ ...f, address: e.target.value }));
            }}
          />
        </div>
        <div className={styles.field} data-testid={`${testIdPrefix}-field-accountCode`}>
          <label className={styles.label}>Tài khoản công nợ</label>
          <SearchInput
            config={accountSearchConfig}
            value={form.accountCode ?? ''}
            primaryDisplay={formatAccountDisplay(form.accountCode ?? '', accountName)}
            disabled={isViewMode}
            onChange={a => {
              markDirty();
              setForm(f => ({ ...f, accountCode: a.code }));
              setAccountName(a.name ?? '');
            }}
            onClear={() => {
              markDirty();
              setForm(f => ({ ...f, accountCode: undefined }));
              setAccountName('');
            }}
            showLabel={false}
            showSecondaryInput={false}
            placeholder="Mã hoặc tên TK..."
          />
        </div>
      </div>
      {sharedCatalog && (!isViewMode || sharedReadOnlyRow) ? (
        <SharedCatalogFormActions
          testIdPrefix={testIdPrefix}
          row={editing}
          currentValues={{
            name: form.name,
            taxCode: form.taxCode,
            phone: form.phone,
            isActive: form.isActive,
          }}
          {...sharedCatalog}
        />
      ) : null}
      {isViewMode ? (
        <div className={styles.viewReadOnlySection}>
          {!hideCompanyField && (
            <CatalogCompanyField testIdPrefix={testIdPrefix} companyName={companyName} />
          )}
          <div className={styles.modalFooterBar} data-testid={`${testIdPrefix}-view-footer`}>
            <div className={styles.modalFooterActive} data-testid={`${testIdPrefix}-field-isActive`}>
              <Checkbox
                label="Đang sử dụng"
                checked={form.isActive ?? true}
                readOnly
                onChange={() => { /* view — không đổi */ }}
              />
            </div>
          </div>
          <div className={styles.modalActionsView}>
            <CatalogFormHistorySlot
              testIdPrefix={testIdPrefix}
              catalogKind="customers"
              editing={editing ? { id: editing.customerId, code: editing.code } : null}
            />
            <Button variant="secondary" onClick={onCancel} data-testid={`${testIdPrefix}-btn-close`}>
              Đóng
            </Button>
          </div>
        </div>
      ) : (
        <CatalogFormFooter
          companyName={companyName}
          testIdPrefix={testIdPrefix}
          checked={form.isActive ?? true}
          onActiveChange={c => {
            markDirty();
            setForm(f => ({ ...f, isActive: c }));
          }}
          onCancel={onCancel}
          onSave={() => { void onSaveClick(); }}
          saving={saving}
          hideCompanyField={hideCompanyField}
          historySlot={
            <CatalogFormHistorySlot
              testIdPrefix={testIdPrefix}
              catalogKind="customers"
              editing={editing ? { id: editing.customerId, code: editing.code } : null}
            />
          }
        />
      )}
    </>
  );
};

export type { CustomerDto };
