import type { CSSProperties } from 'react';
import type { CustomerGroupDto } from '../services/master/models';
import type { SelectOption } from '@linm-soft/common-components';

/** MM Ant Design Table `indentSize={20}` — tree row padding. */
export const CUSTOMER_GROUP_INDENT_PX = 16;

/** Max tree depth — 4 cấp nhóm đối tượng. */
export const MAX_CUSTOMER_GROUP_LEVEL = 4;

export type CustomerGroupTreeRow = CustomerGroupDto & { parentId?: string | null };

/** BE JSON `parentId` → FE `parentCustomerGroupId`. */
export function normalizeCustomerGroupDto(g: CustomerGroupTreeRow): CustomerGroupDto {
  const parentRaw = g.parentCustomerGroupId ?? g.parentId;
  return {
    ...g,
    customerGroupId: String(g.customerGroupId),
    parentCustomerGroupId: parentRaw ? String(parentRaw) : undefined,
  };
}

export function getCustomerGroupParentId(g: CustomerGroupDto): string | null {
  const id = g.parentCustomerGroupId;
  return id ? String(id) : null;
}

/** Mã format nhóm cấp 1 — prefix mã đối tượng dạng {formatCode}.{subprefix} (MasterCode). */
export function resolveLevel1CustomerGroup(
  groupId: string | undefined,
  groups: CustomerGroupDto[],
): CustomerGroupDto | undefined {
  if (!groupId) return undefined;
  const byId = new Map(groups.map(g => [g.customerGroupId, g]));
  let current = byId.get(groupId);
  while (current?.parentCustomerGroupId) {
    current = byId.get(current.parentCustomerGroupId);
  }
  return current;
}

export function resolveLevel1FormatCode(
  groupId: string | undefined,
  groups: CustomerGroupDto[],
): string | undefined {
  return resolveLevel1CustomerGroup(groupId, groups)?.formatCode?.trim() || undefined;
}

/** Mã nhóm cấp 1 theo loại đối tượng (legacy). */
export const CUSTOMER_GROUP_TYPE_CODES: Record<string, string> = {
  Customer: '200',
  Supplier: '300',
  Both: '400',
};

export const CUSTOMER_TYPE_LABELS: Record<string, string> = {
  Customer: 'Khách hàng',
  Supplier: 'Nhà cung cấp',
  Both: 'Cả hai',
};

const TYPE_LABEL_FALLBACK: SelectOption[] = [
  { value: 'Customer', label: 'Khách hàng' },
  { value: 'Supplier', label: 'Nhà cung cấp' },
  { value: 'Both', label: 'Cả hai' },
];

/** Distinct Loại options from loaded nhóm đối tượng (catalog), fallback when empty. */
export function buildCustomerTypeOptionsFromGroups(
  groups: CustomerGroupDto[],
  fallback: SelectOption[] = TYPE_LABEL_FALLBACK,
): SelectOption[] {
  const seen = new Set<string>();
  const opts: SelectOption[] = [];
  for (const g of groups) {
    const t = g.customerType?.trim();
    if (!t || seen.has(t)) continue;
    seen.add(t);
    opts.push({ value: t, label: CUSTOMER_TYPE_LABELS[t] ?? t });
  }
  return opts.length > 0 ? opts : fallback;
}

/** Nhóm đối tượng options for Select (value = customerGroupId). */
export function buildCustomerGroupSelectOptions(groups: CustomerGroupDto[]): SelectOption[] {
  return groups
    .filter(g => g.isActive)
    .sort((a, b) => a.code.localeCompare(b.code, 'vi', { numeric: true }))
    .map(g => ({ value: g.customerGroupId, label: `${g.code} — ${g.name}` }));
}

const defaultSiblingCompare = (a: CustomerGroupDto, b: CustomerGroupDto) =>
  a.code.localeCompare(b.code, 'vi', { numeric: true });

/**
 * Flatten depth-first: cha → con (con ngay dưới cha, thụt lề).
 * Siblings sorted by `compareSiblings` (default: mã).
 */
export function flattenCustomerGroupTree(
  items: CustomerGroupDto[],
  compareSiblings?: (a: CustomerGroupDto, b: CustomerGroupDto) => number,
): CustomerGroupDto[] {
  const compare = compareSiblings ?? defaultSiblingCompare;
  const normalized = items.map(g => normalizeCustomerGroupDto(g));
  const idSet = new Set(normalized.map(g => g.customerGroupId));

  const childrenOf = new Map<string | null, CustomerGroupDto[]>();
  for (const g of normalized) {
    let parentKey = getCustomerGroupParentId(g);
    if (parentKey && !idSet.has(parentKey)) {
      parentKey = null;
    }
    const list = childrenOf.get(parentKey);
    if (list) list.push(g);
    else childrenOf.set(parentKey, [g]);
  }

  for (const list of childrenOf.values()) {
    list.sort(compare);
  }

  const out: CustomerGroupDto[] = [];
  const visit = (parentId: string | null) => {
    for (const g of childrenOf.get(parentId) ?? []) {
      out.push(g);
      visit(g.customerGroupId);
    }
  };
  visit(null);
  return out;
}

export function customerGroupRowIndent(level?: number): number {
  return Math.max(0, (level ?? 1) - 1) * CUSTOMER_GROUP_INDENT_PX;
}

/** Tree depth for grid indent — uses BE `level`. */
export function customerGroupRowDepth(row: CustomerGroupDto): number {
  return Math.max(1, row.level ?? 1);
}

/** Grid cell style from BE fontColor / backgroundColor (nhóm cấp 1). */
export function customerGroupRowCellStyle(row: CustomerGroupDto): CSSProperties | undefined {
  if (!row.backgroundColor && !row.fontColor) return undefined;
  return {
    backgroundColor: row.backgroundColor ?? undefined,
    color: row.fontColor ?? undefined,
  };
}

export type CustomerGroupLevelKeys = {
  idKey: `customerGroup${1 | 2 | 3 | 4}Id`;
  codeKey: `customerGroup${1 | 2 | 3 | 4}Code`;
  nameKey: `customerGroup${1 | 2 | 3 | 4}Name`;
};

export function customerGroupLevelKeys(level: number): CustomerGroupLevelKeys {
  const n = Math.min(4, Math.max(1, level));
  return {
    idKey: `customerGroup${n}Id` as CustomerGroupLevelKeys['idKey'],
    codeKey: `customerGroup${n}Code` as CustomerGroupLevelKeys['codeKey'],
    nameKey: `customerGroup${n}Name` as CustomerGroupLevelKeys['nameKey'],
  };
}

/** Chain từ leaf groupId → patch 4 cấp id/code/name. */
export function resolveCustomerGroupChainPatch(
  leafGroupId: string | undefined,
  groups: CustomerGroupDto[],
): Record<string, string> {
  if (!leafGroupId?.trim()) return {};
  const byId = new Map(groups.map(g => [g.customerGroupId, normalizeCustomerGroupDto(g)]));
  const chain: CustomerGroupDto[] = [];
  let current = byId.get(leafGroupId);
  while (current) {
    chain.unshift(current);
    const parentId = getCustomerGroupParentId(current);
    current = parentId ? byId.get(parentId) : undefined;
  }

  const patch: Record<string, string> = {};
  chain.forEach((g, index) => {
    const level = index + 1;
    const keys = customerGroupLevelKeys(level);
    patch[keys.idKey] = g.customerGroupId;
    patch[keys.codeKey] = g.code;
    patch[keys.nameKey] = g.name;
  });
  return patch;
}

/** Số cấp nhóm trong chuỗi leaf → root (1–4). */
export function resolveCustomerGroupChainDepth(
  leafGroupId: string | undefined,
  groups: CustomerGroupDto[],
): number {
  if (!leafGroupId?.trim()) return 0;
  const patch = resolveCustomerGroupChainPatch(leafGroupId, groups);
  let depth = 0;
  for (let level = 1; level <= MAX_CUSTOMER_GROUP_LEVEL; level += 1) {
    const id = patch[customerGroupLevelKeys(level).idKey];
    if (id?.trim()) depth = level;
  }
  return depth;
}

/** Xóa nhóm từ cấp `fromLevel` đến 4. */
export function clearCustomerGroupsFromLevel(fromLevel: number): Record<string, string> {
  if (fromLevel > 4) return {};
  const patch: Record<string, string> = {};
  for (let level = fromLevel; level <= 4; level += 1) {
    const keys = customerGroupLevelKeys(level);
    patch[keys.idKey] = '';
    patch[keys.codeKey] = '';
    patch[keys.nameKey] = '';
  }
  return patch;
}

/** customerGroupId = nhóm sâu nhất đã chọn (ưu tiên cấp 4 → 1). */
export function resolveLeafCustomerGroupId(
  form: Record<string, unknown>,
): string | undefined {
  for (let level = 4; level >= 1; level -= 1) {
    const id = String(form[customerGroupLevelKeys(level).idKey] ?? '').trim();
    if (id) return id;
  }
  return undefined;
}
